/// The display name for a champion, or `None` if the id is unknown.
pub fn champion_name(champion: Champion) -> Option<&'static str> {
    let index = CHAMPIONS
        .binary_search_by_key(&champion.0, |entry| entry.0)
        .ok()?;

    Some(CHAMPIONS[index].2)
}

